window.GRE_WORDS=[{"id":"aberration","pos":"noun","phonetic":"","zh":"偏差；反常现象","definition":"a departure from what is normal, usual, or expected","example":"The sudden decline was an aberration rather than a lasting trend.","collocations":["an aberration from the norm","statistical aberration"],"etymology":"Latin aberrare, meaning ‘to wander away’","memory":"ab-（离开）+ err（走错）：偏离正常轨道。","level":1,"group":"GRE Core","greTier":"GRE Core","source":"GRE Reading Core"},{"id":"aberrant","pos":"adjective","phonetic":"","zh":"异常的；偏离常规的","definition":"departing from an accepted standard or normal pattern","example":"Researchers repeated the test to explain the aberrant result.","collocations":["aberrant behavior","aberrant pattern"],"etymology":"Latin aberrare, ‘wander away’","memory":"和 aberration 同根：走离正常路线就是异常。","level":1,"group":"GRE Core","greTier":"GRE Core","source":"GRE Reading Core"},{"id":"abhor","pos":"verb","phonetic":"","zh":"憎恶；厌恶","definition":"to regard with intense dislike or disgust","example":"The reformer abhorred the cruelty of the old system.","collocations":["abhor violence","deeply abhor"],"etymology":"Latin abhorrere, ‘shrink back in horror’","memory":"ab-（离开）+ horr（发抖）：厌恶到后退发抖。","level":1,"group":"GRE Core","greTier":"GRE Core","source":"GRE Reading Core"},{"id":"abjure","pos":"verb","phonetic":"","zh":"正式放弃；发誓戒绝","definition":"to renounce a belief, claim, or practice formally","example":"The witness abjured his earlier allegiance to the group.","collocations":["abjure a belief","abjure violence"],"etymology":"Latin abjurare, ‘deny on oath’","memory":"ab-（离开）+ jur（宣誓）：发誓离开、正式放弃。","level":1,"group":"GRE Core","greTier":"GRE Core","source":"GRE Reading Core"},{"id":"abrogate","pos":"verb","phonetic":"","zh":"废除；撤销","definition":"to repeal or do away with a law, right, or agreement","example":"The court ruled that the treaty could not be abrogated unilaterally.","collocations":["abrogate a law","abrogate a treaty"],"etymology":"Latin abrogare, ‘repeal by proposal’","memory":"把规则 rog 回去并拿走，就是撤销。","level":1,"group":"GRE Core","greTier":"GRE Core","source":"GRE Reading Core"},{"id":"acquiesce","pos":"verb","phonetic":"","zh":"默许；勉强同意","definition":"to accept something reluctantly but without protest","example":"After hours of debate, the committee acquiesced to the compromise.","collocations":["acquiesce in a decision","acquiesce to a demand"],"etymology":"Latin acquiescere, ‘become quiet’","memory":"quiet 般安静下来、不再反对，就是默许。","level":1,"group":"GRE Core","greTier":"GRE Core","source":"GRE Reading Core"},{"id":"acrimony","pos":"noun","phonetic":"","zh":"尖刻；激烈争执","definition":"bitterness and hostility in speech or manner","example":"The policy debate ended in acrimony rather than agreement.","collocations":["political acrimony","with growing acrimony"],"etymology":"Latin acer, ‘sharp’","memory":"acr 像 sharp：言辞尖锐，充满敌意。","level":1,"group":"GRE Core","greTier":"GRE Core","source":"GRE Reading Core"},{"id":"acumen","pos":"noun","phonetic":"","zh":"敏锐；洞察力","definition":"the ability to make quick and accurate judgments","example":"Her financial acumen helped the company survive the downturn.","collocations":["business acumen","political acumen"],"etymology":"Latin acuere, ‘to sharpen’","memory":"acu 表示尖锐：判断像刀锋一样敏锐。","level":1,"group":"GRE Core","greTier":"GRE Core","source":"GRE Reading Core"},{"id":"adamant","pos":"adjective","phonetic":"","zh":"坚决的；不动摇的","definition":"refusing to be persuaded or to change one's mind","example":"She remained adamant that the evidence be reviewed independently.","collocations":["remain adamant","adamant refusal"],"etymology":"Greek adamas, ‘unconquerable; diamond’","memory":"像 diamond 一样坚硬，立场不动摇。","level":1,"group":"GRE Core","greTier":"GRE Core","source":"GRE Reading Core"},{"id":"admonish","pos":"verb","phonetic":"","zh":"告诫；责备","definition":"to warn or reprimand someone firmly","example":"The editor admonished the reporter for relying on a single source.","collocations":["admonish someone for","gently admonish"],"etymology":"Latin admonere, ‘bring to mind; warn’","memory":"让某人记在 mind 里，就是告诫。","level":1,"group":"GRE Core","greTier":"GRE Core","source":"GRE Reading Core"},{"id":"aggrandize","pos":"verb","phonetic":"","zh":"扩大；吹捧；提高权势","definition":"to increase the power, status, or reputation of someone or something","example":"The ruler used public monuments to aggrandize his regime.","collocations":["aggrandize oneself","aggrandize power"],"etymology":"French agrandir, ‘make greater’","memory":"grand 是宏大；让它更 grand 就是扩大或吹捧。","level":1,"group":"GRE Core","greTier":"GRE Core","source":"GRE Reading Core"},{"id":"alacrity","pos":"noun","phonetic":"","zh":"欣然；敏捷","definition":"brisk and cheerful readiness","example":"She accepted the difficult assignment with surprising alacrity.","collocations":["with alacrity","show alacrity"],"etymology":"Latin alacritas, ‘eagerness’","memory":"想成 alert + eager：又快又乐意。","level":1,"group":"GRE Core","greTier":"GRE Core","source":"GRE Reading Core"},{"id":"alienate","pos":"verb","phonetic":"","zh":"使疏远；使不友好","definition":"to cause someone to feel isolated or estranged","example":"The dismissive tone alienated readers who might have agreed.","collocations":["alienate voters","feel alienated from"],"etymology":"Latin alienus, ‘belonging to another’","memory":"alien 是陌生人；让人变陌生就是疏远。","level":1,"group":"GRE Core","greTier":"GRE Core","source":"GRE Reading Core"},{"id":"amenable","pos":"adjective","phonetic":"","zh":"愿意接受的；易受影响的","definition":"open and responsive to suggestion or authority","example":"The data are amenable to several different interpretations.","collocations":["amenable to change","amenable to analysis"],"etymology":"Latin minari through French amener, ‘bring or lead’","memory":"能被带向某个方向，所以愿意接受、适合处理。","level":1,"group":"GRE Core","greTier":"GRE Core","source":"GRE Reading Core"},{"id":"anathema","pos":"noun","phonetic":"","zh":"令人憎恶之物；诅咒","definition":"something or someone intensely disliked or rejected","example":"Censorship was anathema to the independent journalist.","collocations":["be anathema to","regard as anathema"],"etymology":"Greek anathema, ‘thing devoted or accursed’","memory":"被公开放逐、诅咒的东西，自然令人憎恶。","level":1,"group":"GRE Core","greTier":"GRE Core","source":"GRE Reading Core"},{"id":"anomalous","pos":"adjective","phonetic":"","zh":"反常的；不规则的","definition":"deviating from what is standard, normal, or expected","example":"The anomalous reading prompted scientists to recalibrate the instrument.","collocations":["anomalous result","anomalous behavior"],"etymology":"Greek anomalos, ‘uneven’","memory":"a-（不）+ normal 的联想：不正常就是反常。","level":1,"group":"GRE Core","greTier":"GRE Core","source":"GRE Reading Core"},{"id":"apocryphal","pos":"adjective","phonetic":"","zh":"真实性可疑的；杜撰的","definition":"of doubtful authenticity although widely repeated","example":"The often-repeated story about the invention is probably apocryphal.","collocations":["apocryphal story","largely apocryphal"],"etymology":"Greek apokruphos, ‘hidden’","memory":"来源藏着看不清，因此真实性可疑。","level":1,"group":"GRE Core","greTier":"GRE Core","source":"GRE Reading Core"},{"id":"appease","pos":"verb","phonetic":"","zh":"安抚；平息","definition":"to calm or satisfy a person or demand by making concessions","example":"Minor reforms failed to appease the protesters.","collocations":["appease critics","attempt to appease"],"etymology":"Old French apaisier, from paix, ‘peace’","memory":"让局面回到 peace，就是安抚、平息。","level":1,"group":"GRE Core","greTier":"GRE Core","source":"GRE Reading Core"},{"id":"approbation","pos":"noun","phonetic":"","zh":"赞许；认可","definition":"official or formal approval or praise","example":"The proposal received the approbation of several leading scholars.","collocations":["win approbation","public approbation"],"etymology":"Latin approbare, ‘approve’","memory":"看到 approv- 就想到 approve：正式赞许。","level":1,"group":"GRE Core","greTier":"GRE Core","source":"GRE Reading Core"},{"id":"artifice","pos":"noun","phonetic":"","zh":"诡计；巧妙手段","definition":"a clever device or deceptive trick","example":"The apparent spontaneity of the speech was a carefully planned artifice.","collocations":["clever artifice","without artifice"],"etymology":"Latin artificium, ‘craftsmanship’","memory":"art +ifice：人工设计的巧妙手段，也可能是诡计。","level":1,"group":"GRE Core","greTier":"GRE Core","source":"GRE Reading Core"},{"id":"artless","pos":"adjective","phonetic":"","zh":"天真的；不做作的","definition":"natural, sincere, and without deception","example":"Her artless response made the rehearsed answers seem evasive.","collocations":["artless sincerity","artless manner"],"etymology":"art + -less, literally ‘without craft’","memory":"没有 craft 和套路，因此天真、不做作。","level":1,"group":"GRE Core","greTier":"GRE Core","source":"GRE Reading Core"},{"id":"audacious","pos":"adjective","phonetic":"","zh":"大胆的；鲁莽的","definition":"showing a bold willingness to take risks","example":"The researchers proposed an audacious explanation for the anomaly.","collocations":["audacious claim","audacious attempt"],"etymology":"Latin audax, ‘bold’","memory":"和 audio 无关；记成敢于大声说出的大胆主张。","level":1,"group":"GRE Core","greTier":"GRE Core","source":"GRE Reading Core"},{"id":"austere","pos":"adjective","phonetic":"","zh":"朴素的；严厉的；苦行的","definition":"severe in manner or plain and without comfort","example":"The building's austere design reflected the movement's ideals.","collocations":["austere lifestyle","austere beauty"],"etymology":"Greek austeros, ‘harsh or bitter’","memory":"画面是没有装饰、条件严苛的房间。","level":1,"group":"GRE Core","greTier":"GRE Core","source":"GRE Reading Core"},{"id":"avaricious","pos":"adjective","phonetic":"","zh":"贪婪的；贪财的","definition":"having an extreme desire for wealth or gain","example":"The novel portrays an avaricious merchant who values profit above loyalty.","collocations":["avaricious appetite","avaricious landlord"],"etymology":"Latin avaritia, ‘greed’","memory":"和 avarice 同根：对财富贪得无厌。","level":1,"group":"GRE Core","greTier":"GRE Core","source":"GRE Reading Core"},{"id":"baleful","pos":"adjective","phonetic":"","zh":"有害的；恶意的","definition":"threatening harm or exerting a harmful influence","example":"The policy had a baleful effect on independent research.","collocations":["baleful influence","baleful glare"],"etymology":"Old English bealu, ‘evil or injury’","memory":"bale 想成灾祸包裹：带来伤害。","level":1,"group":"GRE Core","greTier":"GRE Core","source":"GRE Reading Core"},{"id":"bellicose","pos":"adjective","phonetic":"","zh":"好战的；挑衅的","definition":"demonstrating aggression and willingness to fight","example":"The ambassador's bellicose rhetoric intensified the dispute.","collocations":["bellicose rhetoric","bellicose stance"],"etymology":"Latin bellum, ‘war’","memory":"bell- 表示战争：充满战意就是好战。","level":1,"group":"GRE Core","greTier":"GRE Core","source":"GRE Reading Core"},{"id":"berate","pos":"verb","phonetic":"","zh":"严厉斥责","definition":"to scold or criticize angrily","example":"The coach berated the team for ignoring basic safety rules.","collocations":["berate someone for","publicly berate"],"etymology":"Probably from a prefix be- + rate in an older sense","memory":"想成被 angry rating 连续轰炸，就是严厉斥责。","level":1,"group":"GRE Core","greTier":"GRE Core","source":"GRE Reading Core"},{"id":"blatant","pos":"adjective","phonetic":"","zh":"公然的；极明显的","definition":"done openly and unashamedly; very obvious","example":"The article contained a blatant distortion of the original study.","collocations":["blatant disregard","blatant attempt"],"etymology":"Coined in the sixteenth century; later ‘noisily conspicuous’","memory":"明显到像噪声一样刺眼，就是公然的。","level":1,"group":"GRE Core","greTier":"GRE Core","source":"GRE Reading Core"},{"id":"blithe","pos":"adjective","phonetic":"","zh":"无忧无虑的；漫不经心的","definition":"showing cheerful indifference or casual unconcern","example":"His blithe dismissal of the risks frustrated the engineers.","collocations":["blithe disregard","blithe spirit"],"etymology":"Old English blithe, ‘joyous or gentle’","memory":"快乐过头而不在意风险，就是漫不经心。","level":1,"group":"GRE Core","greTier":"GRE Core","source":"GRE Reading Core"},{"id":"boisterous","pos":"adjective","phonetic":"","zh":"喧闹的；活跃粗放的","definition":"noisy, energetic, and cheerful","example":"The boisterous crowd made quiet discussion impossible.","collocations":["boisterous crowd","boisterous laughter"],"etymology":"Middle English boistous, ‘rough or coarse’","memory":"声音和动作都很粗放，所以喧闹。","level":1,"group":"GRE Core","greTier":"GRE Core","source":"GRE Reading Core"},{"id":"brazen","pos":"adjective","phonetic":"","zh":"厚颜无耻的；公然的","definition":"bold and shameless","example":"The report exposed a brazen attempt to manipulate the figures.","collocations":["brazen attempt","brazen disregard"],"etymology":"Old English bræsen, ‘made of brass’","memory":"脸像 brass 黄铜一样硬，就是厚颜无耻。","level":1,"group":"GRE Core","greTier":"GRE Core","source":"GRE Reading Core"},{"id":"browbeat","pos":"verb","phonetic":"","zh":"威逼；恫吓","definition":"to intimidate someone with stern or abusive words","example":"Officials tried to browbeat the witness into changing her statement.","collocations":["browbeat someone into","attempt to browbeat"],"etymology":"brow + beat, an image of beating down with a frown","memory":"用皱眉和强势言辞压人，就是威逼。","level":1,"group":"GRE Core","greTier":"GRE Core","source":"GRE Reading Core"},{"id":"bucolic","pos":"adjective","phonetic":"","zh":"田园的；乡村生活的","definition":"relating to the pleasant aspects of the countryside","example":"The poem presents a bucolic landscape untouched by industry.","collocations":["bucolic setting","bucolic charm"],"etymology":"Greek boukolos, ‘cowherd’","memory":"牧牛人的乡村画面，就是田园的。","level":1,"group":"GRE Core","greTier":"GRE Core","source":"GRE Reading Core"},{"id":"cacophonous","pos":"adjective","phonetic":"","zh":"刺耳嘈杂的","definition":"involving a harsh mixture of sounds","example":"A cacophonous blend of horns and engines filled the street.","collocations":["cacophonous noise","cacophonous mixture"],"etymology":"Greek kakos ‘bad’ + phone ‘sound’","memory":"caco-（坏）+ phone（声音）：刺耳的声音。","level":1,"group":"GRE Core","greTier":"GRE Core","source":"GRE Reading Core"},{"id":"callow","pos":"adjective","phonetic":"","zh":"幼稚无经验的","definition":"inexperienced and immature","example":"The callow intern mistook confidence for expertise.","collocations":["callow youth","callow newcomer"],"etymology":"Old English calu, ‘bare or bald’","memory":"像尚未长羽毛的小鸟，幼稚又缺经验。","level":1,"group":"GRE Core","greTier":"GRE Core","source":"GRE Reading Core"},{"id":"calumny","pos":"noun","phonetic":"","zh":"诽谤；中伤","definition":"a false statement intended to damage a reputation","example":"The accusation was dismissed as political calumny.","collocations":["malicious calumny","spread calumny"],"etymology":"Latin calumnia, ‘false accusation’","memory":"把它和 false claim 绑定：恶意的虚假指控。","level":1,"group":"GRE Core","greTier":"GRE Core","source":"GRE Reading Core"},{"id":"canard","pos":"noun","phonetic":"","zh":"谣言；虚假报道","definition":"an unfounded story or deliberately false report","example":"The claim that the method had never failed was a persistent canard.","collocations":["old canard","repeat a canard"],"etymology":"French canard, ‘duck’; later ‘fabricated story’","memory":"法语 duck 变成假新闻的旧说法，记作谣言。","level":1,"group":"GRE Core","greTier":"GRE Core","source":"GRE Reading Core"},{"id":"candid","pos":"adjective","phonetic":"","zh":"坦率的；直言不讳的","definition":"truthful and straightforward","example":"The scientist was candid about the limitations of the experiment.","collocations":["candid assessment","candid about"],"etymology":"Latin candidus, ‘white or pure’","memory":"透明洁白、没有遮掩，所以坦率。","level":1,"group":"GRE Core","greTier":"GRE Core","source":"GRE Reading Core"},{"id":"capitulate","pos":"verb","phonetic":"","zh":"投降；停止抵抗","definition":"to cease resisting and accept an opponent's terms","example":"After weeks of pressure, the company capitulated to the union's demands.","collocations":["capitulate to pressure","refuse to capitulate"],"etymology":"Latin capitulum, ‘chapter or heading’; terms of surrender","memory":"在投降条款的标题下签字，就是停止抵抗。","level":1,"group":"GRE Core","greTier":"GRE Core","source":"GRE Reading Core"},{"id":"carping","pos":"adjective","phonetic":"","zh":"吹毛求疵的；爱挑剔的","definition":"continually finding fault about trivial matters","example":"Carping objections distracted from the proposal's central merit.","collocations":["carping criticism","carping tone"],"etymology":"From carp, ‘complain or find fault’","memory":"像不停啄食一样挑小毛病。","level":1,"group":"GRE Core","greTier":"GRE Core","source":"GRE Reading Core"},{"id":"cataclysm","pos":"noun","phonetic":"","zh":"大灾难；剧变","definition":"a sudden violent disaster or major upheaval","example":"The financial cataclysm reshaped public attitudes toward regulation.","collocations":["economic cataclysm","cataclysmic change"],"etymology":"Greek kataklusmos, ‘deluge’","memory":"洪水般席卷一切的大灾难或剧变。","level":1,"group":"GRE Core","greTier":"GRE Core","source":"GRE Reading Core"},{"id":"catalyst","pos":"noun","phonetic":"","zh":"催化剂；促成变化的人或事","definition":"something that speeds up or provokes significant change","example":"The court decision became a catalyst for broader reform.","collocations":["catalyst for change","serve as a catalyst"],"etymology":"Greek katalusis, ‘dissolution’","memory":"化学催化剂加速反应；抽象上加速变化。","level":1,"group":"GRE Core","greTier":"GRE Core","source":"GRE Reading Core"},{"id":"chary","pos":"adjective","phonetic":"","zh":"谨慎的；不愿冒险的","definition":"cautiously reluctant to act or give","example":"Investors remained chary of forecasts based on limited data.","collocations":["chary of","remain chary"],"etymology":"Old English cearig, ‘sorrowful or careful’","memory":"care 的声音联想：因为在意风险而谨慎。","level":1,"group":"GRE Core","greTier":"GRE Core","source":"GRE Reading Core"},{"id":"chicanery","pos":"noun","phonetic":"","zh":"欺骗；诡辩","definition":"the use of trickery or deceptive argument","example":"The audit uncovered accounting chicanery designed to hide losses.","collocations":["legal chicanery","political chicanery"],"etymology":"French chicaner, ‘to quibble’","memory":"不断用话术绕弯、钻空子，就是欺骗诡辩。","level":1,"group":"GRE Core","greTier":"GRE Core","source":"GRE Reading Core"},{"id":"chimera","pos":"noun","phonetic":"","zh":"幻想；不可能实现的想法","definition":"an unrealistic hope or imagined creation","example":"A perfectly objective account may be a chimera rather than an attainable goal.","collocations":["mere chimera","pursue a chimera"],"etymology":"Greek mythic monster Chimaira","memory":"由不同动物拼成的怪兽，象征不真实的幻想。","level":1,"group":"GRE Core","greTier":"GRE Core","source":"GRE Reading Core"},{"id":"choleric","pos":"adjective","phonetic":"","zh":"易怒的；暴躁的","definition":"bad-tempered and easily angered","example":"The choleric director reacted to minor delays with fury.","collocations":["choleric temperament","choleric outburst"],"etymology":"Greek khole, ‘bile’, one of the ancient humors","memory":"古人认为胆汁多会暴躁，因此表示易怒。","level":1,"group":"GRE Core","greTier":"GRE Core","source":"GRE Reading Core"},{"id":"collusion","pos":"noun","phonetic":"","zh":"勾结；串通","definition":"secret cooperation for an illegal or deceptive purpose","example":"The firms were accused of collusion to keep prices artificially high.","collocations":["in collusion with","evidence of collusion"],"etymology":"Latin colludere, ‘play together’","memory":"col-（共同）+ lud（玩）：暗中一起做局。","level":1,"group":"GRE Core","greTier":"GRE Core","source":"GRE Reading Core"},{"id":"condone","pos":"verb","phonetic":"","zh":"宽恕；纵容","definition":"to accept or allow behavior considered wrong","example":"Explaining the decision does not mean condoning it.","collocations":["condone violence","cannot condone"],"etymology":"Latin condonare, ‘give up or forgive’","memory":"把惩罚放下，就是宽恕；过度便是纵容。","level":1,"group":"GRE Core","greTier":"GRE Core","source":"GRE Reading Core"},{"id":"contrite","pos":"adjective","phonetic":"","zh":"悔恨的；痛悔的","definition":"feeling or expressing remorse","example":"He offered a contrite apology after the evidence disproved his claim.","collocations":["contrite apology","genuinely contrite"],"etymology":"Latin conterere, ‘wear down or crush’","memory":"被内疚压碎般难受，就是悔恨。","level":1,"group":"GRE Core","greTier":"GRE Core","source":"GRE Reading Core"},{"id":"convivial","pos":"adjective","phonetic":"","zh":"友好欢快的；适合宴饮的","definition":"friendly, lively, and enjoyable","example":"The seminar ended with a convivial dinner and informal debate.","collocations":["convivial atmosphere","convivial host"],"etymology":"Latin convivium, ‘feast’","memory":"con-（一起）+ viv（生活）：一起欢聚。","level":1,"group":"GRE Core","greTier":"GRE Core","source":"GRE Reading Core"},{"id":"credulity","pos":"noun","phonetic":"","zh":"轻信；易受骗","definition":"a tendency to believe things too readily","example":"The rumor depended on public credulity rather than evidence.","collocations":["strain credulity","exploit credulity"],"etymology":"Latin credere, ‘believe’","memory":"cred 是相信；相信得过快就是轻信。","level":1,"group":"GRE Core","greTier":"GRE Core","source":"GRE Reading Core"},{"id":"cursory","pos":"adjective","phonetic":"","zh":"草率的；粗略的","definition":"hasty and not thorough","example":"A cursory reading misses the argument's crucial qualification.","collocations":["cursory glance","cursory examination"],"etymology":"Latin currere, ‘run’","memory":"像跑过去一样看得很快，所以粗略草率。","level":1,"group":"GRE Core","greTier":"GRE Core","source":"GRE Reading Core"},{"id":"debase","pos":"verb","phonetic":"","zh":"贬低；降低价值或品质","definition":"to reduce in quality, dignity, or value","example":"The critic argued that sensationalism debased public debate.","collocations":["debase the currency","debase a tradition"],"etymology":"de- ‘down’ + base","memory":"把事物压低到 base 水平，就是降低品质。","level":1,"group":"GRE Core","greTier":"GRE Core","source":"GRE Reading Core"},{"id":"decorous","pos":"adjective","phonetic":"","zh":"得体的；合乎礼仪的","definition":"in keeping with good taste and proper behavior","example":"The discussion remained decorous despite strong disagreement.","collocations":["decorous behavior","decorous manner"],"etymology":"Latin decor, ‘grace or propriety’","memory":"和 decor（得体的装饰）同根：合乎礼仪。","level":1,"group":"GRE Core","greTier":"GRE Core","source":"GRE Reading Core"},{"id":"demur","pos":"verb","phonetic":"","zh":"表示异议；犹豫","definition":"to raise an objection or show reluctance","example":"Most members agreed, but two experts demurred.","collocations":["demur at","without demur"],"etymology":"Latin demorari, ‘delay’","memory":"因为有异议而 delay，便是反对或犹豫。","level":1,"group":"GRE Core","greTier":"GRE Core","source":"GRE Reading Core"},{"id":"anodyne","pos":"adjective","phonetic":"","zh":"缓和的；不得罪人的","definition":"unlikely to provoke disagreement or offense","example":"The report offered an anodyne conclusion that avoided the central dispute.","collocations":["anodyne statement","anodyne language"],"etymology":"Greek anodunos, ‘free from pain’","memory":"an-（无）+ odyn（痛）：不痛，也引申为温和无刺激。","level":1,"group":"GRE Advanced","greTier":"GRE Advanced","source":"GRE Reading Core"},{"id":"apotheosis","pos":"noun","phonetic":"","zh":"顶峰；神化","definition":"the highest point of development or elevation to divine status","example":"The cathedral was hailed as the apotheosis of the architectural style.","collocations":["the apotheosis of","reach its apotheosis"],"etymology":"Greek apotheoun, ‘make a god’","memory":"被抬到 god 的高度，就是神化或巅峰。","level":1,"group":"GRE Advanced","greTier":"GRE Advanced","source":"GRE Reading Core"},{"id":"asperity","pos":"noun","phonetic":"","zh":"严厉；粗暴","definition":"harshness of tone or manner","example":"She answered with an asperity that silenced further questions.","collocations":["with asperity","unexpected asperity"],"etymology":"Latin asper, ‘rough’","memory":"asper 表示粗糙：语气粗粝、严厉。","level":1,"group":"GRE Advanced","greTier":"GRE Advanced","source":"GRE Reading Core"},{"id":"atavism","pos":"noun","phonetic":"","zh":"返祖现象；旧习复现","definition":"the reappearance of an ancestral trait or earlier behavior","example":"The policy was criticized as an atavism from a less tolerant era.","collocations":["cultural atavism","political atavism"],"etymology":"Latin atavus, ‘ancestor’","memory":"ancestor 的旧特征重新出现，就是返祖。","level":1,"group":"GRE Advanced","greTier":"GRE Advanced","source":"GRE Reading Core"},{"id":"beatific","pos":"adjective","phonetic":"","zh":"幸福安详的；圣洁喜悦的","definition":"showing serene happiness","example":"A beatific smile spread across her face as the choir began.","collocations":["beatific smile","beatific expression"],"etymology":"Latin beatus, ‘blessed’","memory":"被 blessing 包围的安详喜悦。","level":1,"group":"GRE Advanced","greTier":"GRE Advanced","source":"GRE Reading Core"},{"id":"bilious","pos":"adjective","phonetic":"","zh":"坏脾气的；令人不快的","definition":"bad-tempered or unpleasant","example":"The columnist's bilious attack substituted insult for analysis.","collocations":["bilious mood","bilious attack"],"etymology":"Latin bilis, ‘bile’","memory":"古人把胆汁和坏脾气联系起来。","level":1,"group":"GRE Advanced","greTier":"GRE Advanced","source":"GRE Reading Core"},{"id":"bowdlerize","pos":"verb","phonetic":"","zh":"删改不雅内容","definition":"to remove material considered improper from a text","example":"The school edition bowdlerized several passages from the novel.","collocations":["heavily bowdlerized","bowdlerize a text"],"etymology":"From Thomas Bowdler, editor of an expurgated Shakespeare","memory":"记住 Bowdler 这个人名：删改经典以求‘纯洁’。","level":1,"group":"GRE Advanced","greTier":"GRE Advanced","source":"GRE Reading Core"},{"id":"cadaverous","pos":"adjective","phonetic":"","zh":"尸体般苍白消瘦的","definition":"pale, thin, and resembling a corpse","example":"Weeks of illness left him looking cadaverous.","collocations":["cadaverous face","cadaverous appearance"],"etymology":"Latin cadaver, ‘corpse’","memory":"cadaver 是尸体，-ous 表示具有这种样子。","level":1,"group":"GRE Advanced","greTier":"GRE Advanced","source":"GRE Reading Core"},{"id":"complaisant","pos":"adjective","phonetic":"","zh":"殷勤顺从的；讨好的","definition":"willing to please others or accept their wishes","example":"The complaisant adviser rarely challenged the minister's assumptions.","collocations":["complaisant manner","overly complaisant"],"etymology":"French complaire, ‘to please’","memory":"注意不同于 complacent；这里是努力 please 别人。","level":1,"group":"GRE Advanced","greTier":"GRE Advanced","source":"GRE Reading Core"},{"id":"conflagration","pos":"noun","phonetic":"","zh":"大火；剧烈冲突","definition":"a large destructive fire or violent conflict","example":"A small border dispute threatened to become a regional conflagration.","collocations":["major conflagration","political conflagration"],"etymology":"Latin conflagrare, ‘burn together’","memory":"con-（一起）+ flagr（燃烧）：火势全面蔓延。","level":1,"group":"GRE Advanced","greTier":"GRE Advanced","source":"GRE Reading Core"},{"id":"desideratum","pos":"noun","phonetic":"","zh":"迫切需要之物；理想目标","definition":"something considered necessary or highly desirable","example":"Consistency is a central desideratum of any reliable theory.","collocations":["essential desideratum","major desideratum"],"etymology":"Latin desiderare, ‘desire’","memory":"desire 的正式名词：非常想要、需要的东西。","level":1,"group":"GRE Advanced","greTier":"GRE Advanced","source":"GRE Reading Core"},{"id":"effrontery","pos":"noun","phonetic":"","zh":"厚颜无耻；放肆","definition":"shameless boldness","example":"He had the effrontery to demand praise for work he had opposed.","collocations":["have the effrontery to","sheer effrontery"],"etymology":"French effronté, ‘shameless’, literally ‘without a forehead’","memory":"脸面都不要了，所以厚颜无耻。","level":1,"group":"GRE Advanced","greTier":"GRE Advanced","source":"GRE Reading Core"},{"id":"inchoate","pos":"adjective","phonetic":"","zh":"刚开始的；未成形的","definition":"only partly formed or developed","example":"The movement began as an inchoate collection of local protests.","collocations":["inchoate idea","inchoate movement"],"etymology":"Latin incohare, ‘begin’","memory":"像刚画出的草图，已经开始但尚未成形。","level":1,"group":"GRE Advanced","greTier":"GRE Advanced","source":"GRE Reading Core"},{"id":"inimical","pos":"adjective","phonetic":"","zh":"敌对的；有害的","definition":"hostile to or harmful to something","example":"Excessive secrecy is inimical to scientific collaboration.","collocations":["inimical to","deeply inimical"],"etymology":"Latin inimicus, ‘enemy’","memory":"和 enemy 同源：敌对且有害。","level":1,"group":"GRE Advanced","greTier":"GRE Advanced","source":"GRE Reading Core"},{"id":"intransigent","pos":"adjective","phonetic":"","zh":"不妥协的；顽固的","definition":"unwilling to change one's views or agree","example":"Both sides remained intransigent, and negotiations collapsed.","collocations":["intransigent opposition","remain intransigent"],"etymology":"Spanish intransigente, ‘not compromising’","memory":"in-（不）+ transact 的联想：拒绝达成交易。","level":1,"group":"GRE Advanced","greTier":"GRE Advanced","source":"GRE Reading Core"},{"id":"meretricious","pos":"adjective","phonetic":"","zh":"华而不实的；俗艳的","definition":"apparently attractive but lacking real value","example":"The essay's meretricious style concealed a weak argument.","collocations":["meretricious appeal","meretricious display"],"etymology":"Latin meretrix, ‘prostitute’","memory":"外表吸引却缺乏真实价值，记作华而不实。","level":1,"group":"GRE Advanced","greTier":"GRE Advanced","source":"GRE Reading Core"},{"id":"opprobrium","pos":"noun","phonetic":"","zh":"公然谴责；耻辱","definition":"harsh public criticism or disgrace","example":"The falsified data brought opprobrium upon the laboratory.","collocations":["public opprobrium","heap opprobrium on"],"etymology":"Latin ob ‘against’ + probrum ‘disgrace’","memory":"公众把 disgrace 推向某人，就是公然谴责。","level":1,"group":"GRE Advanced","greTier":"GRE Advanced","source":"GRE Reading Core"},{"id":"recondite","pos":"adjective","phonetic":"","zh":"深奥难懂的","definition":"little known and difficult to understand","example":"The article explains a recondite theory in surprisingly clear language.","collocations":["recondite subject","recondite knowledge"],"etymology":"Latin recondere, ‘hide away’","memory":"知识被藏得很深，所以冷僻难懂。","level":1,"group":"GRE Advanced","greTier":"GRE Advanced","source":"GRE Reading Core"},{"id":"temerity","pos":"noun","phonetic":"","zh":"鲁莽；冒失","definition":"excessive confidence or boldness","example":"She had the temerity to challenge the conclusion without reading the evidence.","collocations":["have the temerity to","sheer temerity"],"etymology":"Latin temeritas, ‘rashness’","memory":"把它和 rash boldness 绑定：大胆过头就是鲁莽。","level":1,"group":"GRE Advanced","greTier":"GRE Advanced","source":"GRE Reading Core"},{"id":"trenchant","pos":"adjective","phonetic":"","zh":"尖锐有力的；切中要害的","definition":"vigorous, incisive, and effective","example":"His trenchant critique exposed the model's hidden assumptions.","collocations":["trenchant criticism","trenchant analysis"],"etymology":"Old French trenchier, ‘to cut’","memory":"像刀切一样直入要害，所以尖锐有力。","level":1,"group":"GRE Advanced","greTier":"GRE Advanced","source":"GRE Reading Core"},{"id":"vituperate","pos":"verb","phonetic":"","zh":"痛斥；辱骂","definition":"to blame or insult in strong language","example":"The pamphlet vituperated opponents instead of answering them.","collocations":["vituperate an opponent","publicly vituperate"],"etymology":"Latin vituperare, ‘censure’","memory":"把它和 violent verbal attack 绑定：用强烈语言痛斥。","level":1,"group":"GRE Advanced","greTier":"GRE Advanced","source":"GRE Reading Core"},{"id":"vociferous","pos":"adjective","phonetic":"","zh":"大声疾呼的；强烈表达的","definition":"loud and forceful in expressing opinions","example":"Vociferous critics demanded an independent investigation.","collocations":["vociferous opposition","vociferous critic"],"etymology":"Latin vox ‘voice’ + ferre ‘carry’","memory":"把 voice 传得很远，便是大声强烈表达。","level":1,"group":"GRE Advanced","greTier":"GRE Advanced","source":"GRE Reading Core"}];
